def _compute_department_summary(self):
    """Aggregate employee metrics by department"""
    for record in self:
        if record.is_frozen:
            continue

        if not record.weekly_line_ids:
            record.department_summary_ids = False
            continue

        # Group employees by department
        dept_data = {}
        for line in record.weekly_line_ids:
            dept = line.employee_id.department_id
            if not dept:
                continue

            if dept.id not in dept_data:
                dept_data[dept.id] = {
                    'department_id': dept.id,
                    'lines': [],
                }
            dept_data[dept.id]['lines'].append(line)

        # Calculate aggregates for each department
        summary_vals = []
        for dept_id, data in dept_data.items():
            lines = data['lines']
            count = len(lines)

            summary_vals.append((0, 0, {
                'department_id': dept_id,
                'prior_week_open_vs_completed': sum(l.prior_week_open_vs_completed for l in lines) / count if count else 0,
                'prior_week_p1_strikes': sum(l.prior_week_p1_strikes for l in lines),
                'week_open_total': sum(l.week_open_total for l in lines),
                'week_missing_date': sum(l.week_missing_date for l in lines),
                'week_completed_total': sum(l.week_completed_total for l in lines),
                'week_progress_percent': sum(l.week_progress_percent for l in lines) / count if count else 0,
                'week_p1_strikes': sum(l.week_p1_strikes for l in lines),
                'week_total_worked': sum(l.week_total_worked for l in lines),
            }))

        record.department_summary_ids = [(5,)] + summary_vals

