            if (blob.size > 10 * 1024 * 1024) {
                alert('Image size exceeds 10MB. Please try again with lower quality.');
                return;
            }

            const reader = new FileReader();
            reader.onloadend = function() {
                addImagePreview(reader.result, `Photo ${images.length + 1}`);
