            const reader = new FileReader();
            reader.onload = function(e) {
                addReceiptPreview(e.target.result, file.name);
            };
            reader.readAsDataURL(file);
        });
        receiptInput.value = '';
    }

    function addReceiptPreview(dataUrl, name) {
        const receiptId = Date.now() + Math.random();
        receipts.push({ id: receiptId, data: dataUrl, name: name });

        const col = document.createElement('div');
        col.className = 'col-md-4 col-6 mb-3';
        col.innerHTML = `
            <div class="card border-success">
                <img src="${dataUrl}" class="card-img-top" style="height: 150px; object-fit: cover;">
                <div class="card-body p-2">
                    <input type="text" class="form-control form-control-sm receipt-name"
                           value="${name}" data-id="${receiptId}" placeholder="Receipt description">
                    <button type="button" class="btn btn-danger btn-sm w-100 mt-2 remove-receipt"
                            data-id="${receiptId}">
                        <i class="fa fa-trash"></i> Remove
                    </button>
                </div>
            </div>
        `;
        receiptPreview.appendChild(col);

        col.querySelector('.remove-receipt').addEventListener('click', function() {
            receipts = receipts.filter(r => r.id != this.dataset.id);
            col.remove();
        });

        col.querySelector('.receipt-name').addEventListener('input', function() {
            const receipt = receipts.find(r => r.id == this.dataset.id);
            if (receipt) {
                receipt.name = this.value;
            }
        });
    }

    function handleTimesheets(files) {
        Array.from(files).forEach(file => {
            const validTypes = ['image/', 'application/pdf', 'application/vnd.ms-excel',
                              'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                              'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'];

            const isValid = validTypes.some(type => file.type.startsWith(type) || file.type === type);

            if (!isValid) {
                alert(`${file.name} is not a supported file type.`);
                return;
            }

            if (file.size > 10 * 1024 * 1024) {
                alert(`${file.name} exceeds 10MB and will be skipped.`);
                return;
            }

            const reader = new FileReader();
            reader.onload = function(e) {
                addTimesheetPreview(e.target.result, file.name, file.type);
            };
            reader.readAsDataURL(file);
        });
        timesheetInput.value = '';
    }

    function addTimesheetPreview(dataUrl, name, fileType) {
        const tsId = Date.now() + Math.random();
        timesheets.push({ id: tsId, data: dataUrl, name: name });

        const col = document.createElement('div');
        col.className = 'col-md-6 mb-3';

        let icon = 'fa-file';
        if (fileType.startsWith('image/')) icon = 'fa-file-image';
        else if (fileType.includes('pdf')) icon = 'fa-file-pdf';
        else if (fileType.includes('excel') || fileType.includes('spreadsheet')) icon = 'fa-file-excel';
        else if (fileType.includes('word') || fileType.includes('document')) icon = 'fa-file-word';

        col.innerHTML = `
            <div class="card border-info">
                <div class="card-body p-2">
                    <div class="d-flex align-items-center">
                        <i class="fa ${icon} fa-3x text-info me-3"></i>
                        <div class="flex-grow-1">
                            <input type="text" class="form-control form-control-sm timesheet-name"
                                   value="${name}" data-id="${tsId}" placeholder="Timesheet description">
                        </div>
                    </div>
                    <button type="button" class="btn btn-danger btn-sm w-100 mt-2 remove-timesheet"
                            data-id="${tsId}">
                        <i class="fa fa-trash"></i> Remove
                    </button>
                </div>
            </div>
        `;
        timesheetPreview.appendChild(col);

        col.querySelector('.remove-timesheet').addEventListener('click', function() {
            timesheets = timesheets.filter(ts => ts.id != this.dataset.id);
            col.remove();
        });

        col.querySelector('.timesheet-name').addEventListener('input', function() {
            const timesheet = timesheets.find(ts => ts.id == this.dataset.id);
            if (timesheet) {
                timesheet.name = this.value;
            }
        });
    }

    form.addEventListener('submit', async function(e) {
        e.preventDefault();

        const formData = {
            project_id: document.getElementById('project_id').value,
            employee_id: document.getElementById('employee_id').value,
            date: document.getElementById('date').value,
            description: document.getElementById('description').value,
            hours_spent: document.getElementById('hours_spent').value || 0,
            materials_used: document.getElementById('materials_used').value,
            issues: document.getElementById('issues').value,
            location: document.getElementById('location').value,
            weather: document.getElementById('weather').value,
            images: images,
            receipts: receipts,
            timesheets: timesheets,
        };

        submitBtn.disabled = true;
        submitBtn.innerHTML = '<span class="spinner-border spinner-border-sm me-2"></span>Submitting...';

        try {
            const response = await fetch('/project/daily/submit', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    jsonrpc: '2.0',
                    method: 'call',
                    params: formData,
                }),
            });

            const result = await response.json();
            console.log('Submit response:', result);

            if (result.result && result.result.success) {
                successMessage.classList.remove('d-none');
                errorMessage.classList.add('d-none');
                document.getElementById('successText').textContent =
                    `${result.result.message} (${result.result.daily_name}) - ID: ${result.result.daily_id}`;

                form.reset();
                const today = new Date();
                const year = today.getFullYear();
                const month = String(today.getMonth() + 1).padStart(2, '0');
                const day = String(today.getDate()).padStart(2, '0');
                dateInput.value = `${year}-${month}-${day}`;
                images = [];
                receipts = [];
                timesheets = [];
                imagePreview.innerHTML = '';
                receiptPreview.innerHTML = '';
                timesheetPreview.innerHTML = '';

                setTimeout(() => {
                    successMessage.classList.add('d-none');
                }, 5000);
            } else {
                throw new Error(result.result?.message || result.error?.message || 'Submission failed');
            }
        } catch (error) {
            errorMessage.classList.remove('d-none');
            successMessage.classList.add('d-none');
            document.getElementById('errorText').textContent = error.message;
        } finally {
            submitBtn.disabled = false;
            submitBtn.innerHTML = '<i class="fa fa-check"></i> Submit Daily Report';
        }
    });
}

